     1→import { useState, useEffect } from "react";
     2→import {
     3→  Dialog,
     4→  DialogContent,
     5→  DialogHeader,
     6→  DialogTitle,
     7→} from "@/components/ui/dialog";
     8→import { Card, CardContent } from "@/components/ui/card";
     9→import { Badge } from "@/components/ui/badge";
    10→import { Button } from "@/components/ui/button";
    11→import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
    12→import { Clock as Clock, CreditCard as CreditCard, CircleCheck as CheckCircle, CircleX as XCircle, UserCheck as UserCheck, ChevronDown as ChevronDown } from "lucide-react";
    13→import { cn } from "@/lib/utils";
    14→import { appointmentService } from "@/services/appointmentService";
    15→import { toast } from "sonner";
    16→
    17→interface ServiceDetail {
    18→  id: string;
    19→  serviceName: string;
    20→  startTime: string;
    21→  endTime: string;
    22→  professional: string;
    23→  price: number;
    24→  status: "Agendado" | "Atendendo" | "Pgto Pendente" | "Pago" | "Cancelado";
    25→}
    26→
    27→interface ModalComandaProps {
    28→  isOpen: boolean;
    29→  onClose: () => void;
    30→  clientName: string;
    31→  date: string;
    32→  services: ServiceDetail[];
    33→  onStatusUpdate?: (serviceId: string, newStatus: ServiceDetail["status"]) => void;
    34→}
    35→
    36→export function ModalComanda({
    37→  isOpen,
    38→  onClose,
    39→  clientName,
    40→  date,
    41→  services,
    42→  onStatusUpdate
    43→}: ModalComandaProps) {
    44→  // Estado local para gerenciar status dos serviços
    45→  const [serviceStatuses, setServiceStatuses] = useState<Record<string, ServiceDetail["status"]>>({});
    46→  const [isUpdating, setIsUpdating] = useState<string | null>(null);
    47→
    48→  // Inicializar estados quando os serviços mudarem
    49→  useEffect(() => {
    50→    const initialStatuses = services.reduce((acc, service) => ({
    51→      ...acc,
    52→      [service.id]: service.status
    53→    }), {});
    54→    setServiceStatuses(initialStatuses);
    55→  }, [services]);
    56→
    57→  // Função para obter status disponíveis baseado no status atual
    58→  const getAvailableStatuses = (currentStatus: ServiceDetail["status"]): ServiceDetail["status"][] => {
    59→    // Lista de todos os status disponíveis (sem "Cancelado")
    60→    const allStatuses: ServiceDetail["status"][] = [
    61→      "Agendado",
    62→      "Atendendo",
    63→      "Pgto Pendente",
    64→      "Pago"
    65→    ];
    66→
    67→    // Retorna todos os status exceto o atual (pode mudar para qualquer outro)
    68→    return allStatuses.filter(status => status !== currentStatus);
    69→  };
    70→
    71→  // Configuração de cores e ícones por status
    72→  const getStatusConfig = (status: ServiceDetail["status"]) => {
    73→    switch (status) {
    74→      case "Agendado":
    75→        return {
    76→          icon: Clock,
    77→          bgColor: "bg-blue-50",
    78→          textColor: "text-blue-700",
    79→          iconColor: "text-blue-500"
    80→        };
    81→      case "Atendendo":
    82→        return {
    83→          icon: UserCheck,
    84→          bgColor: "bg-orange-50",
    85→          textColor: "text-orange-700",
    86→          iconColor: "text-orange-500"
    87→        };
    88→      case "Pgto Pendente":
    89→        return {
    90→          icon: CreditCard,
    91→          bgColor: "bg-yellow-50",
    92→          textColor: "text-yellow-700",
    93→          iconColor: "text-yellow-500"
    94→        };
    95→      case "Pago":
    96→        return {
    97→          icon: CheckCircle,
    98→          bgColor: "bg-green-50",
    99→          textColor: "text-green-700",
   100→          iconColor: "text-green-500"
   101→        };
   102→      case "Cancelado":
   103→        return {
   104→          icon: XCircle,
   105→          bgColor: "bg-red-50",
   106→          textColor: "text-red-700",
   107→          iconColor: "text-red-500"
   108→        };
   109→      default:
   110→        return {
   111→          icon: Clock,
   112→          bgColor: "bg-muted",
   113→          textColor: "text-foreground",
   114→          iconColor: "text-muted-foreground"
   115→        };
   116→    }
   117→  };
   118→
   119→  // Função para alterar status do serviço e persistir no backend
   120→  const handleStatusChange = async (serviceId: string, newStatus: ServiceDetail["status"]) => {
   121→    // Mapear status para o formato do backend
   122→    const statusMap: Record<ServiceDetail["status"], string> = {
   123→      "Agendado": "scheduled",
   124→      "Atendendo": "in_progress",
   125→      "Pgto Pendente": "completed",
   126→      "Pago": "paid", // Este será tratado de forma especial
   127→      "Cancelado": "cancelled" // Mantido para compatibilidade com dados existentes
   128→    };
   129→    
   130→    // Verificar o status atual do serviço
   131→    const currentStatus = serviceStatuses[serviceId] || services.find(s => s.id === serviceId)?.status;
   132→    const currentBackendStatus = statusMap[currentStatus as ServiceDetail["status"]];
   133→    const newBackendStatus = statusMap[newStatus];
   134→    
   135→    // Não permitir transição para o mesmo status
   136→    if (currentStatus === newStatus) {
   137→      return; // Silenciosamente ignorar se for o mesmo status
   138→    }
   139→    
   140→    // LIBERADO: Permitir todas as transições entre todos os status
   141→    // Removida validação de transições - agora qualquer status pode ir para qualquer outro
   142→    // Isso dá flexibilidade total para o salão gerenciar seus agendamentos
   143→    
   144→    setIsUpdating(serviceId);
   145→    
   146→    try {
   147→      // Se o novo status for "Pago", usar o endpoint de pagamento
   148→      if (newStatus === "Pago") {
   149→        // Buscar o preço do serviço
   150→        const service = services.find(s => s.id === serviceId);
   151→        await appointmentService.updatePayment(serviceId, {
   152→          paymentStatus: "paid" as any,
   153→          paymentMethod: "cash" as any, // Default para dinheiro, pode ser melhorado depois
   154→        });
   155→      } else {
   156→        // Para outros status, usar o endpoint de status normal
   157→        await appointmentService.updateStatus(serviceId, {
   158→          status: statusMap[newStatus] as any
   159→        });
   160→      }
   161→      
   162→      // Atualizar estado local após sucesso
   163→      setServiceStatuses(prev => ({
   164→        ...prev,
   165→        [serviceId]: newStatus
   166→      }));
   167→      
   168→      // Notificar o componente pai sobre a atualização
   169→      onStatusUpdate?.(serviceId, newStatus);
   170→      
   171→      toast.success(`Status atualizado para ${newStatus}`);
   172→    } catch (error: any) {
   173→      const errorMessage = error?.response?.data?.message || 'Erro ao atualizar status';
   174→      toast.error(errorMessage);
   175→    } finally {
   176→      setIsUpdating(null);
   177→    }
   178→  };
   179→
   180→  // Ordenar serviços: "Pago" vai para o final
   181→  const sortedServices = [...services].sort((a, b) => {
   182→    const statusA = serviceStatuses[a.id] || a.status;
   183→    const statusB = serviceStatuses[b.id] || b.status;
   184→    
   185→    if (statusA === "Pago" && statusB !== "Pago") return 1;
   186→    if (statusB === "Pago" && statusA !== "Pago") return -1;
   187→    return 0;
   188→  });
   189→
   190→  return (
   191→    <Dialog open={isOpen} onOpenChange={onClose}>
   192→      <DialogContent 
   193→        className="w-[95vw] md:max-w-2xl max-h-[90vh] p-0 gap-0 rounded-xl md:rounded-2xl border-none shadow-2xl overflow-hidden flex flex-col" /* RESP: Dimensões padrão */
   194→        onInteractOutside={(e) => e.preventDefault()}
   195→      >
   196→        <DialogHeader className="sticky top-0 z-10 bg-background px-5 py-4 border-b shrink-0 text-left"> {/* RESP: Header fixo e padding padrão */}
   197→          <DialogTitle className="text-xl font-bold text-primary"> {/* RESP: Cor primária no título */}
   198→            Comanda – {clientName}
   199→          </DialogTitle>
   200→          <div className="flex items-center gap-2 mt-1">
   201→            <Badge variant="outline" className="font-normal text-xs bg-muted/50 border-muted-foreground/20">
   202→              {date}
   203→            </Badge>
   204→          </div>
   205→        </DialogHeader>
   206→
   207→        <div className="flex-1 overflow-y-auto px-5 py-6 custom-scrollbar"> {/* RESP: Área de scroll com padding padrão */}
   208→          <div className="space-y-6">
   209→            <div className="flex items-center justify-between">
   210→              <h3 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Serviços Agendados</h3>
   211→              <Badge variant="secondary" className="text-[10px] font-bold">
   212→                {sortedServices.length} {sortedServices.length === 1 ? 'ITEM' : 'ITENS'}
   213→              </Badge>
   214→            </div>
   215→            
   216→            {sortedServices.length === 0 ? (
   217→              <div className="flex flex-col items-center justify-center py-12 text-center space-y-3">
   218→                <div className="p-4 bg-muted/30 rounded-full">
   219→                  <Clock className="h-8 w-8 text-muted-foreground/40" />
   220→                </div>
   221→                <p className="text-sm text-muted-foreground max-w-[200px]">
   222→                  Nenhum serviço agendado para este cliente nesta data.
   223→                </p>
   224→              </div>
   225→            ) : (
   226→              <div className="space-y-4">
   227→                {sortedServices.map((service) => {
   228→                  const currentStatus = serviceStatuses[service.id] || service.status;
   229→                  const { icon: StatusIcon, bgColor, textColor, iconColor } = getStatusConfig(currentStatus);
   230→                  const isPaid = currentStatus === "Pago";
   231→                  
   232→                  return (
   233→                    <Card key={service.id} className="overflow-hidden border-muted/60 shadow-sm hover:shadow-md transition-shadow">
   234→                      <CardContent className="p-0">
   235→                        <div className="flex flex-col sm:flex-row sm:items-center">
   236→                          {/* Barra de Status Lateral no Mobile / Superior no Desktop */}
   237→                          <div className={cn("w-full sm:w-2 sm:self-stretch", bgColor)} />
   238→                          
   239→                          <div className="flex-1 p-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
   240→                            <div className="space-y-1.5">
   241→                              <div className="flex flex-wrap items-center gap-2">
   242→                                <span className="font-bold text-base">{service.serviceName}</span>
   243→                                
   244→                                {isPaid ? (
   245→                                  <Badge className={cn("border-0 text-[10px] px-2 h-5", bgColor, textColor)}>
   246→                                    <StatusIcon className={cn("h-3 w-3 mr-1", iconColor)} />
   247→                                    {currentStatus.toUpperCase()}
   248→                                  </Badge>
   249→                                ) : (
   250→                                  <DropdownMenu>
   251→                                    <DropdownMenuTrigger asChild>
   252→                                      <Button
   253→                                        variant="ghost"
   254→                                        size="sm"
   255→                                        disabled={isUpdating === service.id || getAvailableStatuses(currentStatus).length === 0}
   256→                                        className={cn(
   257→                                          "h-6 py-0 px-2 font-bold text-[10px] gap-1 rounded-full",
   258→                                          bgColor,
   259→                                          textColor,
   260→                                          "hover:opacity-80"
   261→                                        )}
   262→                                      >
   263→                                        <StatusIcon className={cn("h-3 w-3", iconColor)} />
   264→                                        {isUpdating === service.id ? "..." : currentStatus.toUpperCase()}
   265→                                        {getAvailableStatuses(currentStatus).length > 0 && (
   266→                                          <ChevronDown className="h-3 w-3 opacity-50" />
   267→                                        )}
   268→                                      </Button>
   269→                                    </DropdownMenuTrigger>
   270→                                    <DropdownMenuContent align="start" className="w-48">
   271→                                      {getAvailableStatuses(currentStatus).map((status) => {
   272→                                        const config = getStatusConfig(status);
   273→                                        const OptionIcon = config.icon;
   274→                                        return (
   275→                                          <DropdownMenuItem
   276→                                            key={status}
   277→                                            onClick={() => handleStatusChange(service.id, status)}
   278→                                            className="text-xs font-medium py-2"
   279→                                          >
   280→                                            <div className={cn("p-1 rounded-md mr-2", config.bgColor)}>
   281→                                              <OptionIcon className={cn("h-3 w-3", config.iconColor)} />
   282→                                            </div>
   283→                                            {status}
   284→                                          </DropdownMenuItem>
   285→                                        );
   286→                                      })}
   287→                                    </DropdownMenuContent>
   288→                                  </DropdownMenu>
   289→                                )}
   290→                              </div>
   291→                              
   292→                              <div className="flex items-center gap-x-3 gap-y-1 flex-wrap text-sm text-muted-foreground font-medium">
   293→                                <span className="flex items-center gap-1">
   294→                                  <Clock className="h-3 w-3" />
   295→                                  {service.startTime} – {service.endTime}
   296→                                </span>
   297→                                <span className="flex items-center gap-1">
   298→                                  <UserCheck className="h-3 w-3" />
   299→                                  {service.professional}
   300→                                </span>
   301→                                <span className="sm:hidden font-bold text-primary ml-auto">
   302→                                  R$ {(Number(service.price) || 0).toFixed(2).replace('.', ',')}
   303→                                </span>
   304→                              </div>
   305→                            </div>
   306→                            
   307→                            <div className="hidden sm:block text-right">
   308→                              <div className="text-xs text-muted-foreground font-medium mb-0.5">Valor</div>
   309→                              <div className="text-lg font-black text-primary">
   310→                                R$ {(Number(service.price) || 0).toFixed(2).replace('.', ',')}
   311→                              </div>
   312→                            </div>
   313→                          </div>
   314→                        </div>
   315→                      </CardContent>
   316→                    </Card>
   317→                  );
   318→                })}
   319→              </div>
   320→            )}
   321→          </div>
   322→        </div>
   323→
   324→        <div className="sticky bottom-0 z-10 bg-background px-5 py-4 border-t shrink-0 flex flex-col sm:flex-row sm:justify-end gap-3"> {/* RESP: Footer fixo com padding padrão */}
   325→          <Button 
   326→            variant="outline" 
   327→            onClick={onClose}
   328→            className="w-full sm:w-auto font-bold"
   329→          >
   330→            Fechar Comanda
   331→          </Button>
   332→        </div>
   333→      </DialogContent>
   334→    </Dialog>
   335→  );
   336→}

