     1→import { useRef, useMemo, useEffect, useState, useCallback } from "react";
     2→import { isBefore, startOfDay } from "date-fns";
     3→import { toZonedTime, formatInTimeZone } from "date-fns-tz";
     4→import { Loader2 as Loader2 } from "lucide-react";
     5→import { cn } from "@/lib/utils";
     6→import { getUserDisplayName } from "@/utils/userHelpers";
     7→import { EasyCalendarProps, ProfessionalColumn as ProfessionalColumnType, TimeSlot } from "./types";
     8→import { TimeGrid } from "./TimeGrid";
     9→import { ProfessionalColumn } from "./ProfessionalColumn";
    10→
    11→const BASE_SLOT_HEIGHT = 50; // px per 15-minute slot
    12→const BASE_SLOT_MINUTES = 15;
    13→const MOBILE_COLUMN_WIDTH = 160; // px
    14→const DESKTOP_COLUMN_WIDTH = 300; // px
    15→
    16→const getInitials = (name: string): string => {
    17→  const parts = name.trim().split(" ").filter(Boolean);
    18→  if (parts.length >= 2) {
    19→    return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
    20→  }
    21→  return name.substring(0, 2).toUpperCase();
    22→};
    23→
    24→const generateTimeSlots = (
    25→  startHour: number,
    26→  endHour: number,
    27→  slotMinutes: number
    28→): TimeSlot[] => {
    29→  const slots: TimeSlot[] = [];
    30→  let currentHour = startHour;
    31→  let currentMinute = 0;
    32→
    33→  while (
    34→    currentHour < endHour ||
    35→    (currentHour === endHour && currentMinute === 0)
    36→  ) {
    37→    const label = `${currentHour.toString().padStart(2, "0")}:${currentMinute
    38→      .toString()
    39→      .padStart(2, "0")}`;
    40→    const time = `${currentHour}:${currentMinute.toString().padStart(2, "0")}`;
    41→
    42→    slots.push({
    43→      hour: currentHour,
    44→      minute: currentMinute,
    45→      label,
    46→      time,
    47→    });
    48→
    49→    currentMinute += slotMinutes;
    50→    if (currentMinute >= 60) {
    51→      currentMinute = 0;
    52→      currentHour += 1;
    53→    }
    54→  }
    55→
    56→  return slots;
    57→};
    58→
    59→const calculateCurrentTimePosition = (
    60→  currentDate: Date,
    61→  timeSlots: TimeSlot[],
    62→  slotHeight: number,
    63→  timezone?: string
    64→): number | undefined => {
    65→  if (timeSlots.length === 0) return undefined;
    66→
    67→  // Get current time in the salon's timezone
    68→  // We need to extract hours and minutes in the salon's timezone, not local browser timezone
    69→  const currentHour = timezone
    70→    ? parseInt(formatInTimeZone(currentDate, timezone, "HH"), 10)
    71→    : currentDate.getHours();
    72→  const currentMinute = timezone
    73→    ? parseInt(formatInTimeZone(currentDate, timezone, "mm"), 10)
    74→    : currentDate.getMinutes();
    75→
    76→  const firstSlot = timeSlots[0];
    77→  const currentTotalMinutes = currentHour * 60 + currentMinute;
    78→  const firstSlotMinutes = firstSlot.hour * 60 + firstSlot.minute;
    79→
    80→  // If current time is before the first slot, return 0
    81→  if (currentTotalMinutes < firstSlotMinutes) return 0;
    82→
    83→  const minutesFromFirst = currentTotalMinutes - firstSlotMinutes;
    84→
    85→  const slotMinutes =
    86→    timeSlots.length > 1
    87→      ? timeSlots[1].hour * 60 + timeSlots[1].minute - firstSlotMinutes
    88→      : 15;
    89→
    90→  const position = (minutesFromFirst / slotMinutes) * slotHeight;
    91→
    92→  return position;
    93→};
    94→
    95→export const EasyCalendar: React.FC<EasyCalendarProps> = ({
    96→  date,
    97→  columns,
    98→  events,
    99→  startHour = 8,
   100→  endHour = 20,
   101→  slotMinutes = 15,
   102→  primaryColor,
   103→  salonTimezone = "America/Sao_Paulo",
   104→  onEventClick,
   105→  onEventMove,
   106→  onSlotClick,
   107→  onAbsenceClick,
   108→  onAbsenceBlockClick,
   109→  loading = false,
   110→  isSalonClosed = false,
   111→  focusAppointment = null,
   112→  onFocusConsumed,
   113→  containerClassName,
   114→}) => {
   115→  const scrollContainerRef = useRef<HTMLDivElement>(null);
   116→  const headerScrollRef = useRef<HTMLDivElement>(null);
   117→  const [currentTime, setCurrentTime] = useState(new Date());
   118→  const [scrollbarWidth, setScrollbarWidth] = useState(0);
   119→
   120→  const timeSlots = useMemo(
   121→    () => generateTimeSlots(startHour, endHour, slotMinutes),
   122→    [startHour, endHour, slotMinutes]
   123→  );
   124→
   125→  // Calculate slot height dynamically based on slot minutes
   126→  // 15 minutes = 50px (base), 30 minutes = 100px, etc.
   127→  const slotHeight = useMemo(
   128→    () => (slotMinutes / BASE_SLOT_MINUTES) * BASE_SLOT_HEIGHT,
   129→    [slotMinutes]
   130→  );
   131→
   132→  const calendarDate = useMemo(() => {
   133→    // Parse date string as UTC to ensure consistent behavior across timezones
   134→    // The date string comes in format YYYY-MM-DD and represents a date in UTC
   135→    return new Date(date + "T00:00:00.000Z");
   136→  }, [date]);
   137→
   138→  // Check if it's today in the salon's timezone
   139→  const isTodayDate = useMemo(() => {
   140→    // Get current date in salon's timezone
   141→    const nowInSalonTz = toZonedTime(new Date(), salonTimezone);
   142→    const todayInSalonTz = formatInTimeZone(
   143→      nowInSalonTz,
   144→      salonTimezone,
   145→      "yyyy-MM-dd"
   146→    );
   147→
   148→    return date === todayInSalonTz;
   149→  }, [date, salonTimezone]);
   150→
   151→  const isPastDay = useMemo(
   152→    () => isBefore(startOfDay(calendarDate), startOfDay(new Date())),
   153→    [calendarDate]
   154→  );
   155→
   156→  const currentTimePosition = useMemo(() => {
   157→    // Always show current time marker on today, regardless of past/future
   158→    if (!isTodayDate) return undefined;
   159→    return calculateCurrentTimePosition(
   160→      currentTime,
   161→      timeSlots,
   162→      slotHeight,
   163→      salonTimezone
   164→    );
   165→  }, [isTodayDate, currentTime, timeSlots, slotHeight, salonTimezone]);
   166→
   167→  useEffect(() => {
   168→    if (!isTodayDate) return;
   169→    const interval = setInterval(() => setCurrentTime(new Date()), 60000);
   170→    return () => clearInterval(interval);
   171→  }, [isTodayDate]);
   172→
   173→  // Sync header horizontal scroll with body scroll
   174→  const handleBodyScroll = useCallback(() => {
   175→    if (scrollContainerRef.current && headerScrollRef.current) {
   176→      headerScrollRef.current.scrollLeft = scrollContainerRef.current.scrollLeft;
   177→    }
   178→  }, []);
   179→
