    73→// Função de busca inteligente que ignora case, acentos e permite busca parcial
    74→const normalizeString = (str: string): string => {
    75→  return str
    76→    .toLowerCase()
    77→    .normalize('NFD')
    78→    .replace(/[\u0300-\u036f]/g, '') // Remove acentos
    79→    .replace(/[^a-z0-9\s]/g, ''); // Remove caracteres especiais
    80→};
    81→
    82→// Função de busca flexível que funciona com diferentes formatos de texto
    83→const smartSearch = (searchTerm: string, target: string): boolean => {
    84→  const normalizedSearch = normalizeString(searchTerm);
    85→  const normalizedTarget = normalizeString(target);
    86→
    87→  // Busca exata
    88→  if (normalizedTarget.includes(normalizedSearch)) {
    89→    return true;
    90→  }
    91→
    92→  // Busca por palavras separadas (permite buscar "jo si" para encontrar "João Silva")
    93→  const searchWords = normalizedSearch.split(/\s+/).filter(word => word.length > 0);
    94→  return searchWords.every(word => normalizedTarget.includes(word));
    95→};
