   304→  // Filtrar profissionais baseado na especialidade/serviço selecionado
   305→  useEffect(() => {
   306→    const filterProfessionalsBySpecialty = async () => {
   307→      let filteredProfessionals: Professional[] = allProfessionals;
   308→
   309→      // Se há serviços específicos selecionados, buscar profissionais desses serviços
   310→      if (selectedServices.length > 0) {
   311→        try {
