   325→                    id: prof.userId || prof.professionalId || prof.id,
   326→                    name: prof.userName || prof.professionalName || prof.name || 'Profissional'
   327→                  }));
   328→
   329→                // Adicionar ao cache
   330→                professionalsByServiceCache.set(serviceId, mappedProfessionals);
   331→                return mappedProfessionals;
   332→              } catch {
   333→                return [];
   334→              }
