   338→          // Combinar e remover duplicatas (profissionais que atendem qualquer um dos serviços)
   339→          const allServiceProfessionals = professionalsByService.flat();
   340→          filteredProfessionals = Array.from(
   341→            new Map(allServiceProfessionals.map(prof => [prof.id, prof])).values()
   342→          );
   343→
   344→          setProfessionals(filteredProfessionals);
