    16→}
    17→
    18→export const WOW_MOMENT_STORAGE_KEY = 'easysalon:wow_moment_pending';
    19→export const WOW_MOMENT_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours
    20→export const WOW_MOMENT_EVENTS = ['appointment:created', 'request:created'] as const;
    21→
    22→// MUTEX — fora do hook, nível de módulo
    23→// Sobrevive a re-montagens. Zerado apenas quando o módulo é recarregado (F5).
    24→let wowMomentConsumed = false;
    25→
    26→// Exportar APENAS para uso em testes (reset entre casos)
    27→export function _resetWowMomentConsumedForTests() {
    28→    wowMomentConsumed = false;
    29→}
    30→
    31→export function useWowMoment({
    32→    setSelectedDate,
    33→    refreshAppointments,
    34→}: UseWowMomentProps): UseWowMomentReturn {
    35→    const { isConnected } = useWebSocket();
    36→
    37→    // Lazy initialize isAwaitingAi reading from sessionStorage
    38→    const [isAwaitingAi, setIsAwaitingAi] = useState(
    39→        () => sessionStorage.getItem(WOW_MOMENT_STORAGE_KEY) === 'true'
    40→    );
    41→    const navigate = useNavigate();
    42→
    43→    // Keep stable references for state updaters to use in the event callback safely
    44→    const refreshRef = useRef(refreshAppointments);
    45→    const setDateRef = useRef(setSelectedDate);
    46→
    47→    useEffect(() => {
    48→        // Inicialização
    49→    }, [isAwaitingAi, isConnected]);
    50→
    51→    // Update refs when props change
    52→    useEffect(() => {
    53→        refreshRef.current = refreshAppointments;
    54→        setDateRef.current = setSelectedDate;
    55→    }, [refreshAppointments, setSelectedDate]);
    56→
    57→    // Main listener logic
    58→    useEffect(() => {
    59→        if (!isAwaitingAi || !isConnected) {
    60→            return;
    61→        }
    62→
    63→
    64→
    65→        const handleWowEvent = (eventData: any, eventType: string) => {
    66→            // Check module-level mutex
    67→            if (wowMomentConsumed) {
    68→                return;
    69→            }
    70→
    71→            // Mark as consumed immediately in the same tick
    72→            wowMomentConsumed = true;
    73→            sessionStorage.removeItem(WOW_MOMENT_STORAGE_KEY);
    74→            setIsAwaitingAi(false);
    75→
    76→            if (ttlTimerRef.current) {
    77→                clearTimeout(ttlTimerRef.current);
    78→            }
    79→
    80→            const dateString = eventData.startTime || eventData.finalDate || eventData.preferredDate;
    81→            let parsedDate: Date;
    82→
    83→            if (!dateString) {
    84→                parsedDate = new Date();
    85→            } else {
    86→                parsedDate = new Date(dateString);
    87→            }
    88→
    89→            const clientName = eventData.client?.name || eventData.customerName || "Novo cliente";
    90→            const source = (eventData.source || '').toLowerCase();
    91→            const isRequest = eventType === 'request:created';
    92→
    93→            let toastTitle = '';
    94→            let toastMessage = '';
    95→            let showSparkles = false;
    96→
    97→            if (isRequest) {
    98→                if (source === 'whatsapp' || source === 'ia') {
    99→                    toastTitle = 'Solicitação recebida pela IA!';
   100→                    toastMessage = `${clientName} solicitou um horário com o robô para ${format(parsedDate, "HH:mm")}.`;
   101→                    showSparkles = true;
   102→                } else if (source === 'online') {
   103→                    toastTitle = 'Nova Solicitação Online!';
   104→                    toastMessage = `${clientName} enviou uma solicitação pelo link para ${format(parsedDate, "HH:mm")}.`;
   105→                } else if (source === 'app') {
   106→                    toastTitle = 'Nova Solicitação via App!';
   107→                    toastMessage = `${clientName} enviou uma solicitação pelo aplicativo para ${format(parsedDate, "HH:mm")}.`;
   108→                } else {
   109→                    toastTitle = 'Nova Solicitação Criada!';
   110→                    toastMessage = `Solicitação de ${clientName} registrada para ${format(parsedDate, "HH:mm")}.`;
   111→                }
   112→            } else {
   113→                if (source === 'whatsapp' || source === 'ia') {
   114→                    toastTitle = 'Agendamento realizado pela IA!';
   115→                    toastMessage = `${clientName} interagiu com o robô para ${format(parsedDate, "HH:mm")}.`;
   116→                    showSparkles = true;
   117→                } else if (source === 'online') {
   118→                    toastTitle = 'Novo Agendamento Online!';
   119→                    toastMessage = `${clientName} agendou pelo seu link para ${format(parsedDate, "HH:mm")}.`;
   120→                } else if (source === 'app') {
   121→                    toastTitle = 'Novo Agendamento via App!';
   122→                    toastMessage = `${clientName} agendou pelo aplicativo para ${format(parsedDate, "HH:mm")}.`;
   123→                } else {
   124→                    toastTitle = 'Novo Agendamento Criado!';
   125→                    toastMessage = `Agendamento de ${clientName} registrado para ${format(parsedDate, "HH:mm")}.`;
   126→                }
   127→            }
   128→
   129→            if (isRequest) {
   130→                navigate('/salon/solicitacoes');
   131→            } else {
   132→                setDateRef.current(parsedDate);
   133→                refreshRef.current();
   134→            }
   135→
   136→            toast.success(
   137→                React.createElement(
   138→                    "div",
   139→                    { className: "flex flex-col gap-1" },
   140→                    React.createElement(
   141→                        "span",
   142→                        { className: `font-bold flex items-center gap-2 text-base ${showSparkles ? '' : 'text-foreground'}` },
   143→                        showSparkles && React.createElement(Sparkles, { className: "w-5 h-5 text-yellow-500 fill-yellow-500 animate-pulse" }),
   144→                        toastTitle
   145→                    ),
   146→                    React.createElement(
   147→                        "span",
   148→                        { className: "text-sm text-muted-foreground" },
   149→                        toastMessage
   150→                    )
   151→                ),
   152→                {
   153→                    duration: 8000,
   154→                    className: "bg-card border-2 border-primary/20 shadow-xl",
   155→                }
   156→            );
   157→        };
   158→
   159→        const unsubscribeAppointment = websocketService.on("appointment:created", (data) => handleWowEvent(data, 'appointment:created'));
   160→        const unsubscribeRequest = websocketService.on("request:created", (data) => handleWowEvent(data, 'request:created'));
   161→
   162→        // Setup TTL timer
   163→        const ttlTimerRef = {
   164→            current: setTimeout(() => {
   165→                wowMomentConsumed = true;
   166→                sessionStorage.removeItem(WOW_MOMENT_STORAGE_KEY);
   167→                setIsAwaitingAi(false);
   168→            }, WOW_MOMENT_TTL_MS)
   169→        };
   170→
   171→
   172→        return () => {
   173→            unsubscribeAppointment();
   174→            unsubscribeRequest();
   175→            clearTimeout(ttlTimerRef.current);
   176→        };
   177→
   178→    }, [isConnected, isAwaitingAi]);
   179→
   180→    return {
   181→        isAwaitingAi,
   182→    };
   183→}
   184→

