    13→
    14→export const PasswordRequirements = ({ password, confirmPassword }: PasswordRequirementsProps) => {
    15→  const requirements: PasswordRequirement[] = [
    16→    {
    17→      label: "Senhas coincidem",
    18→      met: password === confirmPassword && password.length > 0,
    19→      tested: password.length > 0 && confirmPassword.length > 0
    20→    },
    21→    {
    22→      label: "8 caracteres",
    23→      met: password.length >= 8,
    24→      tested: password.length > 0
    25→    },
    26→    {
    27→      label: "1 letra maiúscula",
    28→      met: /[A-Z]/.test(password),
    29→      tested: password.length > 0
    30→    },
    31→    {
    32→      label: "1 letra minúscula", 
    33→      met: /[a-z]/.test(password),
    34→      tested: password.length > 0
    35→    },
    36→    {
    37→      label: "1 número",
    38→      met: /\d/.test(password),
    39→      tested: password.length > 0
    40→    },
    41→    {
    42→      label: "1 caractere especial (!, @, #, $)",
    43→      met: /[!@#$]/.test(password),
    44→      tested: password.length > 0
    45→    }
    46→  ];
    47→
    48→  return (
    49→    <div className="space-y-2">
