    62→          }
    63→        }
    64→
    65→        return (
    66→          <div key={index} className="flex items-center gap-2">
    67→            <Icon className={`w-4 h-4 ${iconColor}`} />
    68→            <span className={`text-sm ${iconColor}`}>{req.label}</span>
    69→          </div>
    70→        );
    71→      })}
    72→      
    73→      <p className="text-xs text-muted-foreground mt-4">
