    26→interface ModalNovaAusenciaProps {
    27→  isOpen: boolean;
    28→  onClose: () => void;
    29→  profissional: string;
    30→  profissionalId?: string;
    31→  data: string; // Para exibição no modal
    32→  selectedDate?: Date; // Date object para processamento correto (evita problemas de timezone)
