    43→
    44→export function ModalNovaAusencia({
    45→  isOpen,
    46→  onClose,
    47→  profissional,
    48→  profissionalId,
    49→  data,
    50→  selectedDate,
    51→  horarioInicio,
    52→  isEditing = false,
    53→  ausenciaId,
    54→  horarioFimInicial,
    55→  motivoInicial,
    56→  onAbsenceCreated,
    57→  onAbsenceUpdated,
    58→  onAbsenceDeleted,
    59→}: ModalNovaAusenciaProps) {
    60→  const { selectedSalon } = useSelectedSalon();
    61→  const [horarioInicioAusencia, setHorarioInicioAusencia] =
    62→    useState<string>("");
    63→  const [horarioFim, setHorarioFim] = useState<string>("");
    64→  const [motivo, setMotivo] = useState<string>("");
    65→  const [isLoading, setIsLoading] = useState(false);
    66→  const [timeSlots, setTimeSlots] = useState<TimeSlot[]>([]);
    67→  const [isLoadingSlots, setIsLoadingSlots] = useState(false);
    68→  const [motivoError, setMotivoError] = useState<string>("");
    69→
    70→  // Buscar slots disponíveis quando o modal abrir
    71→  useEffect(() => {
    72→    const fetchAvailableSlots = async () => {
    73→      if (!isOpen || !profissionalId || !selectedDate || !selectedSalon) return;
    74→
    75→      setIsLoadingSlots(true);
    76→      try {
    77→        const dateStr = format(selectedDate, "yyyy-MM-dd");
    78→        const response = await absenceService.getAvailableTimeSlots(
    79→          profissionalId,
    80→          dateStr,
    81→          isEditing ? ausenciaId : undefined
    82→        );
    83→
    84→        // Formatar slots para mostrar apenas horários no timezone do salão
    85→        const salonTimezone = selectedSalon.timezone || "America/Sao_Paulo";
    86→        const formattedSlots = response.slots.map((slot) => {
    87→          // Se o slot já está no formato HH:mm, manter como está
    88→          if (/^\d{2}:\d{2}$/.test(slot.slot)) {
    89→            return slot;
    90→          }
    91→
    92→          // Se for uma data ISO (UTC), converter para timezone local do salão
    93→          const formattedTime = formatUTCToLocal(slot.slot, salonTimezone, "HH:mm");
    94→          return {
    95→            slot: formattedTime,
    96→            available: slot.available,
    97→          };
    98→        });
    99→
   100→        setTimeSlots(formattedSlots);
   101→      } catch (error: any) {
   102→        console.error("Erro ao buscar horários disponíveis:", error);
   103→        toast.error("Erro ao carregar horários disponíveis");
   104→        setTimeSlots([]);
   105→      } finally {
   106→        setIsLoadingSlots(false);
   107→      }
   108→    };
   109→
   110→    fetchAvailableSlots();
   111→  }, [isOpen, profissionalId, selectedDate, isEditing, ausenciaId, selectedSalon]);
   112→
   113→  // Inicializar dados quando o modal abrir
   114→  useEffect(() => {
   115→    if (isOpen) {
   116→      if (isEditing) {
   117→        // Modo edição: carregar dados da ausência existente
   118→        setHorarioInicioAusencia(horarioInicio);
   119→        setHorarioFim(horarioFimInicial || "");
   120→        setMotivo(motivoInicial || "");
   121→        setMotivoError("");
   122→      } else {
   123→        // Modo criação: usar horário clicado
   124→        setHorarioInicioAusencia(horarioInicio);
   125→        setHorarioFim("");
   126→        setMotivo("");
   127→        setMotivoError("");
   128→      }
   129→    }
   130→  }, [isOpen, isEditing, horarioInicio, horarioFimInicial, motivoInicial]);
   131→
   132→  // Gerar opções de horário de início (apenas disponíveis, exceto o último)
   133→  // O último horário não pode ser selecionado como início pois não haveria horário de fim disponível
   134→  const opcoesHorarioInicio = (() => {
   135→    const availableSlots = timeSlots.filter((slot) => slot.available);
   136→    // Se só há um slot disponível, não permite criar ausência
   137→    if (availableSlots.length <= 1) return [];
   138→    // Remove o último slot da lista de opções de início
   139→    return availableSlots.slice(0, -1).map((slot) => slot.slot);
   140→  })();
   141→  /**
   142→   * Verifica se um horário já passou considerando o timezone do salão
   143→   *
   144→   * As datas do backend vêm em UTC e precisam ser convertidas para o timezone do salão
   145→   *
   146→   * @param timeString - Horário no formato "HH:mm"
   147→   * @returns true se já passou (deve bloquear), false se ainda não passou (deve habilitar)
   148→   */
   149→  const isTimeSlotPassed = (timeString: string): boolean => {
   150→    if (!selectedDate || !selectedSalon?.timezone) {
   151→      return false;
   152→    }
   153→
   154→    const salonTimezone = selectedSalon.timezone || "America/Sao_Paulo";
   155→
   156→    // Obter data e hora atual no timezone do salão
   157→    const now = new Date();
   158→    const nowInSalonTz = formatInTimeZone(
   159→      now,
   160→      salonTimezone,
   161→      "yyyy-MM-dd HH:mm"
   162→    );
   163→    const [currentDateStr, currentTimeStr] = nowInSalonTz.split(" ");
   164→
   165→    // Obter data selecionada formatada
   166→    // selectedDate já representa o dia correto em UTC
   167→    const selectedDateStr = format(selectedDate, "yyyy-MM-dd");
   168→
   169→    // Se a data selecionada é anterior a hoje, todos os horários já passaram
   170→    if (selectedDateStr < currentDateStr) {
   171→      return true;
   172→    }
   173→
   174→    // Se a data selecionada é posterior a hoje, nenhum horário passou
   175→    if (selectedDateStr > currentDateStr) {
   176→      return false;
   177→    }
   178→
   179→    // Se é hoje, comparar os horários
   180→    // Converter horários para minutos desde meia-noite para comparação fácil
   181→    const [currentHour, currentMinute] = currentTimeStr.split(":").map(Number);
   182→    const currentMinutes = currentHour * 60 + currentMinute;
   183→
   184→    const [slotHour, slotMinute] = timeString.split(":").map(Number);
   185→    const slotMinutes = slotHour * 60 + slotMinute;
   186→
   187→    // Bloqueia se o horário é menor ou igual ao atual
   188→    return slotMinutes <= currentMinutes;
   189→  };
   190→
   191→  // Gerar opções de horário de fim (todos os slots após o início selecionado)
   192→  const opcoesHorarioFim = (() => {
   193→    if (!horarioInicioAusencia) return [];
   194→
   195→    const [horaInicio, minutoInicio] = horarioInicioAusencia
   196→      .split(":")
   197→      .map(Number);
   198→    const minutosInicio = horaInicio * 60 + minutoInicio;
   199→
   200→    return timeSlots
   201→      .filter((slot) => {
   202→        const [hora, minuto] = slot.slot.split(":").map(Number);
   203→        const minutos = hora * 60 + minuto;
   204→        return minutos > minutosInicio; // Horário de fim deve ser posterior ao início
   205→      })
   206→      .map((slot) => slot.slot);
   207→  })();
   208→
   209→  const handleSalvar = async () => {
   210→    if (!selectedSalon?.id || !profissionalId) {
   211→      toast.error("Informações do salão ou profissional não encontradas");
   212→      return;
   213→    }
   214→
   215→    if (!horarioFim || !motivo) {
   216→      toast.error("Por favor, preencha todos os campos obrigatórios");
