   218→    }
   219→
   220→    if (motivo.trim().length < 3) {
   221→      setMotivoError("O motivo deve ter pelo menos 3 caracteres");
   222→      return;
   223→    }
   224→
   225→    setIsLoading(true);
   226→
   227→    try {
   228→      // Usar Date object se disponível, caso contrário usar data atual
   229→      const dateToUse = selectedDate || new Date();
   230→      const dateStr = format(dateToUse, "yyyy-MM-dd");
   231→
   232→      // Converter horários locais do salão para UTC
   233→      const salonTimezone = selectedSalon?.timezone || "America/Sao_Paulo";
   234→      const startDateTime = convertLocalToUTC(
   235→        dateStr,
   236→        horarioInicioAusencia,
   237→        salonTimezone
   238→      ).toISOString();
   239→      const endDateTime = convertLocalToUTC(
   240→        dateStr,
