   252→        toast.success("Ausência atualizada com sucesso");
   253→        onAbsenceUpdated?.();
   254→      } else {
   255→        // Create new absence
   256→        await absenceService.create({
   257→          userId: profissionalId,
   258→          salonId: selectedSalon.id,
   259→          type: AbsenceType.OTHER,
   260→          reason: motivo,
