   267→        toast.success("Ausência registrada com sucesso");
   268→        onAbsenceCreated?.();
   269→      }
   270→
   271→      onClose();
   272→    } catch (error: any) {
   273→      console.error("Erro ao salvar ausência:", error);
   274→      const errorMessage =
   275→        error.response?.data?.message || "Erro ao salvar ausência";
   276→      toast.error(errorMessage);
