   219→                intervals.push({
   220→                  id: `${dayName}-1`,
   221→                  startTime: startTime,
   222→                  endTime: firstBreak.start,
   223→                });
   224→                // Turno da tarde (depois do intervalo)
   225→                intervals.push({
   226→                  id: `${dayName}-2`,
   227→                  startTime: firstBreak.end,
   228→                  endTime: endTime,
   229→                });
   230→              } else if (
   231→                professionalSchedule.breakStart &&
   232→                professionalSchedule.breakEnd
   233→              ) {
   234→                // Formato antigo com breakStart/breakEnd
   235→                intervals.push({
   236→                  id: `${dayName}-1`,
   237→                  startTime: startTime,
   238→                  endTime: professionalSchedule.breakStart,
   239→                });
   240→                intervals.push({
   241→                  id: `${dayName}-2`,
   242→                  startTime: professionalSchedule.breakEnd,
   243→                  endTime: endTime,
   244→                });
   245→              } else {
   246→                // Turno único (sem intervalo)
   247→                intervals.push({
   248→                  id: `${dayName}-1`,
   249→                  startTime: startTime,
   250→                  endTime: endTime,
   251→                });
   252→              }
   253→
   254→              dayIntervals[dayName] = intervals;
   255→            }
   256→            // Caso 2: Profissional NÃO tem horário customizado OU não trabalha neste dia
   257→            // Usar horários do SALÃO como padrão
   258→            else if (!isProfessionalWorking) {
