   287→  const onSubmit = async (data: ScheduleFormData): Promise<void> => {
   288→    if (!userId) return;
   289→
   290→    // Prevent multiple submissions
   291→    if (loading) return;
   292→
   293→    try {
   294→      setLoading(true);
   295→
   296→      // Convert form format to backend format with numeric keys
   297→      const schedule: Record<
   298→        string,
   299→        {
   300→          isWorking: boolean;
   301→          startTime?: string;
   302→          endTime?: string;
   303→          breakStart?: string;
   304→          breakEnd?: string;
   305→        }
   306→      > = {};
   307→
   308→      // Initialize all days as not working
   309→      for (let i = 0; i <= 6; i++) {
   310→        schedule[i.toString()] = { isWorking: false };
   311→      }
   312→
   313→      if (data.schedule) {
   314→        const { selectedDays, dayIntervals } = data.schedule;
   315→
   316→        // Check if user is clearing all schedule
   317→        const isClearing = !selectedDays || selectedDays.length === 0;
   318→
   319→        if (!isClearing) {
   320→          selectedDays?.forEach((dayName: string) => {
   321→            const dayNum = dayNameToNumber[dayName];
   322→            if (dayNum !== undefined) {
   323→              const intervals = dayIntervals?.[dayName];
   324→              if (intervals && intervals.length > 0) {
   325→                // Sort intervals by start time
   326→                const sortedIntervals = [...intervals].sort((a, b) => {
   327→                  const timeA = a.startTime
   328→                    ? parseInt(a.startTime.replace(":", ""))
   329→                    : 0;
   330→                  const timeB = b.startTime
   331→                    ? parseInt(b.startTime.replace(":", ""))
   332→                    : 0;
   333→                  return timeA - timeB;
   334→                });
   335→
   336→                if (sortedIntervals.length === 1) {
   337→                  // Single shift - no break
   338→                  schedule[dayNum] = {
   339→                    isWorking: true,
   340→                    startTime: sortedIntervals[0].startTime,
   341→                    endTime: sortedIntervals[0].endTime,
   342→                  };
   343→                } else if (sortedIntervals.length === 2) {
   344→                  // Two shifts - implicit break between them
   345→                  const breakStart = sortedIntervals[0].endTime;
   346→                  const breakEnd = sortedIntervals[1].startTime;
   347→
   348→                  // Só adicionar break se houver intervalo real (diferença > 0)
   349→                  if (breakStart !== breakEnd) {
   350→                    schedule[dayNum] = {
   351→                      isWorking: true,
   352→                      startTime: sortedIntervals[0].startTime,
   353→                      endTime: sortedIntervals[1].endTime,
   354→                      breakStart: breakStart,
   355→                      breakEnd: breakEnd,
   356→                    };
   357→                  } else {
   358→                    // Se não há break (turnos consecutivos), tratar como turno único
   359→                    schedule[dayNum] = {
   360→                      isWorking: true,
   361→                      startTime: sortedIntervals[0].startTime,
   362→                      endTime: sortedIntervals[1].endTime,
   363→                    };
   364→                  }
   365→                }
   366→              }
   367→            }
   368→          });
   369→        }
   370→      }
   371→
   372→      // First update the schedule
   373→      await userService.updateSchedule(userId, schedule);
   374→
   375→      // Then update the acceptsOnlineBooking flag if it's set
   376→      if (data.schedule?.acceptsOnlineBooking !== undefined) {
   377→        await userService.update(userId, {
   378→          acceptsOnlineBooking: data.schedule.acceptsOnlineBooking,
   379→        });
   380→      }
   381→      toast.success("Horários salvos com sucesso!");
   382→      navigate("/salon/users");
   383→    } catch (error) {
   384→      const errorObj = error as { response?: { data?: { message?: string } } };
