   831→
   832→    const startMinutes = startHour * 60 + startMinute;
   833→    const endMinutes = endHour * 60 + endMinute;
   834→
   835→    let newDuration = endMinutes - startMinutes;
   836→
   837→    // Se o horário final for menor que o inicial, assumir dia seguinte
   838→    if (newDuration <= 0) {
