   210→                      <p className="text-[13px] text-foreground font-normal truncate mt-0.5">
   211→                        {col.render
   212→                          ? col.render(
   213→                              (row as Record<string, unknown>)[String(col.key)],
   214→                              row
   215→                            )
   216→                          : String(
   217→                              (row as Record<string, unknown>)[
   218→                                String(col.key)
   219→                              ] || "-"
   220→                            )}
   221→                      </p>
   222→                    </div>
   223→                  ))}
   224→              </div>
   225→
   226→              {actionsColForMobile && (
   227→                <div className="pt-2 flex justify-end">
   228→                  {actionsColForMobile.render?.(null, row)}
