   240→
   241→      {/* Tabela Desktop */}
   242→      <div
   243→        className={cn(
   244→          "salon-card overflow-x-auto w-full rounded-lg",
   245→          mobileView === "cards" && "hidden md:block"
   246→        )}
   247→      >
   248→        <Table className="min-w-[600px]">
   249→          <TableHeader>
   250→            <TableRow className="salon-table-header hover:bg-tertiary">
   251→              {table.getFlatHeaders().map((header, index) => {
   252→                const col = allColumns.find(
   253→                  (c) => String(c.key) === header.id
   254→                );
   255→                return (
   256→                  <TableHead
   257→                    key={header.id}
   258→                    className={cn(
   259→                      "text-[13px] font-bold text-foreground whitespace-nowrap",
   260→                      col?.key !== ACTIONS_COLUMN_KEY && "pl-4",
   261→                      col?.className
