   638→
   639→                let errorMessage =
   640→                  "Não foi possível cancelar a solicitação. Tente novamente.";
   641→                if (
   642→                  errorResponse.response?.data?.message?.includes("performedBy")
   643→                ) {
   644→                  errorMessage =
   645→                    "Erro no servidor: problema com o histórico de alterações. Entre em contato com o suporte.";
   646→                } else if (errorResponse.response?.data?.message) {
   647→                  errorMessage = errorResponse.response.data.message;
   648→                }
   649→
   650→                toast({
   651→                  title: "Erro ao cancelar",
   652→                  description: errorMessage,
   653→                  variant: "destructive",
   654→                });
   655→              }
   656→            }
   657→          }}
   658→          itemName={itemToCancel?.name}
   659→        />
   660→      </div>
   661→    </EasySalonLayout>
   662→  );
   663→}
